var e=[{id:`L4_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`……레, 레이 선배?`,JPN:`……レ、レイ先輩？`,ENG:`...R-Ray?`,TWN:`……雷，雷伊前輩？`},stage:{bg:`THRONE`,slots:{L:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L5_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_CA_NULL`,text:{KOREA:`저 자가 지금 마왕을…… 살해한 건가요?`,JPN:`あの者が今、魔王を……殺害したんですか？`,ENG:`Did that person just... kill the Demon Lord?`,TWN:`那個人現在是……把魔王殺掉了嗎？`},stage:{bg:`THRONE`,slots:{L:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_IDLE`}}}},{id:`L7_1`,type:`dialog`,speaker:`HILDE_FENRIR_NEXT_NULL`,text:{KOREA:`나유빈!!`,JPN:`イチノセ・カオル！！`,ENG:`Na Yubin!`,TWN:`羅瑜斌！！`},stage:{bg:`THRONE`,slots:{L:null,C:{char_id:`HILDE_FENRIR_NEXT_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`SAVIOR_KNIGHT_NULL_NULL`,text:{KOREA:`쿨럭……!`,JPN:`ゴホッ……！`,ENG:`*Cough*...!`,TWN:`咳咳……！`},stage:{bg:`THRONE`,slots:{L:null,C:{char_id:`SAVIOR_KNIGHT_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`SAVIOR_KNIGHT_NULL_NULL`,text:{KOREA:`설마… 배신을…?`,JPN:`まさか……裏切りを……？`,ENG:`You... betrayed me...?`,TWN:`是你……背叛了我嗎……？`},stage:{bg:`THRONE`,slots:{L:null,C:{char_id:`SAVIOR_KNIGHT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`NAYUBIN_SIX_NULL_NULL`,text:{KOREA:`배신이라니, 설마요.`,JPN:`裏切りなんて、まさか。`,ENG:`Betray you? Of course not.`,TWN:`背叛？怎麼會呢？`},stage:{bg:`THRONE`,slots:{L:null,C:{char_id:`NAYUBIN_SIX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`NAYUBIN_SIX_NULL_NULL`,text:{KOREA:`처음부터 우리의 동맹은 당신의 멋진 최후를 위한 것 아니었나요?`,JPN:`最初から僕たちの同盟は、あなたの素敵な最期のためのものだったじゃないですか？`,ENG:`Our little alliance was set up for the sole purpose of your wonderful demise.`,TWN:`從一開始，我們結盟不就是為了能讓你有精彩的結局嗎？`},stage:{bg:`THRONE`,slots:{L:null,C:{char_id:`NAYUBIN_SIX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`NAYUBIN_SIX_NULL_NULL`,text:{KOREA:`전 그저 당신이 원하는 바를 이뤄드렸을 뿐입니다.`,JPN:`私はただあなたの望みを叶えてあげたまでですよ。`,ENG:`I simply gave you what you asked for.`,TWN:`我只是幫你實現願望而已。`},stage:{bg:`THRONE`,slots:{L:null,C:{char_id:`NAYUBIN_SIX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`SAVIOR_KNIGHT_NULL_NULL`,text:{KOREA:`당신……. 처음부터…….`,JPN:`あなた……最初から……`,ENG:`You... knew...`,TWN:`你……從一開始……`},stage:{bg:`THRONE`,slots:{L:{char_id:`SAVIOR_KNIGHT_NULL_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`NAYUBIN_SIX_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L16_1`,type:`dialog`,speaker:`SAVIOR_KNIGHT_NULL_NULL`,text:{KOREA:`전부……. 알고 있었으면서…….`,JPN:`全部……わかっていて……`,ENG:`From the very start...`,TWN:`就……全知道一切……`},stage:{bg:`THRONE`,slots:{L:{char_id:`SAVIOR_KNIGHT_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`NAYUBIN_SIX_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L18_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`레이 선배!!`,JPN:`レイ先輩！！`,ENG:`Ray!`,TWN:`雷伊前輩！！`},stage:{bg:`THRONE`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`HILDE_FENRIR_NEXT_NULL`,text:{KOREA:`나유빈! 지금 대체 무슨 짓을 한 거야?!`,JPN:`イチノセ・カオル！　いったい何の真似だ！？`,ENG:`Na Yubin! What have you done?!`,TWN:`羅瑜斌！你到底在做什麼？！`},stage:{bg:`THRONE`,slots:{L:null,C:{char_id:`HILDE_FENRIR_NEXT_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`HILDE_FENRIR_NEXT_NULL`,text:{KOREA:`네가 무슨 짓을 한 건지 알고는 있어?!`,JPN:`貴様が今何をしたかわかっているのか！？`,ENG:`Do you even realize what you just did?!`,TWN:`你知道自己做了什麼嗎？！`},stage:{bg:`THRONE`,slots:{L:null,C:{char_id:`HILDE_FENRIR_NEXT_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`NAYUBIN_SIX_NULL_NULL`,text:{KOREA:`그럼요. 아주 잘 알고 있습니다. 스승님.`,JPN:`ええ。よくわかっていますよ。師匠。`,ENG:`Of course. I am very much aware, Master.`,TWN:`當然。我很清楚，師父。`},stage:{bg:`MS_1103`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:`NAYUBIN_SIX_NULL_NULL`,text:{KOREA:`실패한 대적자는 죽어서 허신이 되거나, 살아서 마왕이 되죠.`,JPN:`失敗した敵対者は死んで虚神になるか、生き残って魔王になる。`,ENG:`A failed Antagonist either dies and becomes a Hollow God, or lives to be the Demon Lord.`,TWN:`失敗的敵對者要不就死掉變成幻神，要不就活著變成魔王。`},stage:{bg:`MS_1103`,slots:{L:null,C:null,R:null}}},{id:`L25_1`,type:`dialog`,speaker:`NAYUBIN_SIX_NULL_NULL`,text:{KOREA:`그래서야 결국 아무것도 구원할 수 없어요.`,JPN:`それじゃ結局、何も救えません。`,ENG:`But that won't save anything.`,TWN:`最終誰都救贖不了。`},stage:{bg:`MS_1103`,slots:{L:null,C:null,R:null}}}];export{e as default};